procedure ComputePUM;
var
  i, j: integer;
begin
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
        PUM[i, j] := PUM_DIAG[i]
      else
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
          ORR: PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
    end;
  end;
end;

procedure ComputeFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      allTrue := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          allTrue := false;
          Break;
        end;
      end;
      FUV[i] := allTrue;
    end;
  end;
end;

procedure ComputeLaunch;
var
