program LIPDecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Classes, Math;

const
  PI = 3.1415926535;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 1..15;
  NPOINTS     = 2..100;
  NPTYPE      = 3..100;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : NPOINTS;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : NPOINTS;
    QUADS    : NUMQUADS;
    DIST     : real;
    N_PTS    : NPTYPE;
    K_PTS    : POINTRANGE;
    A_PTS    : POINTRANGE;
    B_PTS    : POINTRANGE;
    C_PTS    : POINTRANGE;
    D_PTS    : POINTRANGE;
    E_PTS    : POINTRANGE;
    F_PTS    : POINTRANGE;
    G_PTS    : POINTRANGE;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  PUM_DIAG: array[LICRANGE] of boolean;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Distance(i, j: integer): real;
begin
  Distance := Sqrt(Sqr(X[i] - X[j]) + Sqr(Y[i] - Y[j]));
end;

function TriangleArea(i, j, k: integer): real;
begin
  TriangleArea := Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (X[k] - X[i]) * (Y[j] - Y[i])) / 2.0;
end;

function GetQuadrant(i: integer): integer;
begin
  if X[i] > 0 then
  begin
    if Y[i] >= 0 then
      GetQuadrant := 1
    else
      GetQuadrant := 4;
  end
  else if X[i] < 0 then
  begin
    if Y[i] >= 0 then
      GetQuadrant := 2
    else
      GetQuadrant := 3;
  end
  else
  begin
    if Y[i] >= 0 then
      GetQuadrant := 1
    else
      GetQuadrant := 3;
  end;
end;

function CountQuadrants(startIdx, count: integer): integer;
var
  quadSet: array[1..4] of boolean;
  i, q, idx: integer;
begin
  for i := 1 to 4 do
    quadSet[i] := false;

  for i := 0 to count - 1 do
  begin
    idx := startIdx + i;
    q := GetQuadrant(idx);
    quadSet[q] := true;
  end;

  CountQuadrants := 0;
  for i := 1 to 4 do
    if quadSet[i] then
      Inc(CountQuadrants);
end;

function Circumradius(i, j, k: integer): real;
var
  a, b, c, area: real;
begin
  a := Distance(i, j);
  b := Distance(j, k);
  c := Distance(i, k);
  area := TriangleArea(i, j, k);

  if REALCOMPARE(area, 0.0) = EQ then
    Circumradius := 0.0
  else
    Circumradius := (a * b * c) / (4.0 * area);
end;

function AngleAtVertex(i, j, k: integer): real;
var
  ax, ay, bx, by: real;
  dotProd, magA, magB, cosAngle: real;
begin
  ax := X[i] - X[j];
  ay := Y[i] - Y[j];
  bx := X[k] - X[j];
  by := Y[k] - Y[j];

  dotProd := ax * bx + ay * by;
  magA := Sqrt(Sqr(ax) + Sqr(ay));
  magB := Sqrt(Sqr(bx) + Sqr(by));

  if (REALCOMPARE(magA, 0.0) = EQ) or (REALCOMPARE(magB, 0.0) = EQ) then
  begin
    AngleAtVertex := -1.0;
    Exit;
  end;

  cosAngle := dotProd / (magA * magB);
  if cosAngle > 1.0 then
    cosAngle := 1.0
  else if cosAngle < -1.0 then
    cosAngle := -1.0;

  AngleAtVertex := ArcCos(cosAngle);
end;

function PointLineDistance(ptIdx, lineStartIdx, lineEndIdx: integer): real;
var
  x1, y1, x2, y2, x3, y3: real;
  dx, dy, num, denom: real;
begin
  x1 := X[lineStartIdx];
  y1 := Y[lineStartIdx];
  x2 := X[lineEndIdx];
  y2 := Y[lineEndIdx];
  x3 := X[ptIdx];
  y3 := Y[ptIdx];

  dx := x2 - x1;
  dy := y2 - y1;

  if (REALCOMPARE(dx, 0.0) = EQ) and (REALCOMPARE(dy, 0.0) = EQ) then
  begin
    PointLineDistance := Sqrt(Sqr(x3 - x1) + Sqr(y3 - y1));
    Exit;
  end;

  num := Abs(dy * x3 - dx * y3 + x2 * y1 - y2 * x1);
  denom := Sqrt(Sqr(dx) + Sqr(dy));

  PointLineDistance := num / denom;
end;

function CheckLIC1: boolean;
var
  i: integer;
begin
  CheckLIC1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(Distance(i, i + 1), PARAMETERS.LENGTH1) = GT then
    begin
      CheckLIC1 := true;
      Exit;
    end;
  end;
end;

function CheckLIC2: boolean;
var
  i: integer;
begin
  CheckLIC2 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if REALCOMPARE(Circumradius(i, i + 1, i + 2), PARAMETERS.RADIUS1) = GT then
    begin
      CheckLIC2 := true;
      Exit;
    end;
  end;
end;

function CheckLIC3: boolean;
var
  i: integer;
  angle: real;
begin
  CheckLIC3 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := AngleAtVertex(i, i + 1, i + 2);
    if angle >= 0.0 then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CheckLIC3 := true;
        Exit;
      end;
    end;
  end;
end;

function CheckLIC4: boolean;
var
  i: integer;
begin
  CheckLIC4 := false;
  for i := 1 to NUMPOINTS - 2 do
